create table "_Role"
(
    "Id"               bigint generated by default as identity
        constraint "PK__Role"
            primary key,
    "Name"             varchar(256),
    "NormalizedName"   varchar(256),
    "ConcurrencyStamp" text
);

alter table "_Role"
    owner to bcrpro;

create unique index "RoleNameIndex"
    on "_Role" ("NormalizedName");

grant select on "_Role" to dev_read;

